  int Integral = num;
  double fractional = num - Integral;
  while ( Integral > 0 ) {
    int rem = Integral % 2;
    binary . push_back ( rem + '0' );
    Integral /= 2;
  }
  reverse ( binary . begin ( ), binary . end ( ) );
  binary . push_back ( '.' );
  while ( k_prec -- > 0 ) {
    fractional *= 2;
